const seeds = $input.all();
const outputs = [];
for (const seed of seeds) {
  const { id, concept, primary_lang } = seed.json;
  const formats = ['thread', 'carousel', 'reel_script', 'short_script'];
  const cycleNum = Math.floor(Date.now() / (6 * 3600000)) % 4;
  const selectedFormat = formats[cycleNum];
  outputs.push({
    json: {
      concept,
      formats: [selectedFormat],
      langs: [primary_lang || 'it'],
      platforms: selectedFormat === 'thread' ? ['twitter'] : (selectedFormat === 'carousel' ? ['instagram', 'linkedin'] : (selectedFormat === 'reel_script' ? ['tiktok', 'instagram'] : ['youtube'])),
      source_seed_id: id
    }
  });
}
return outputs;

const crypto = require('crypto');
const secret = process.env.WEBHOOK_HMAC_SECRET;

if (!secret) {
  return [{ json: { __hmac_error: 'WEBHOOK_HMAC_SECRET not configured', statusCode: 500 } }];
}

const signature = $json.$headers?.['x-adoff-signature'];
const body = $json.$body || JSON.stringify($json);

if (process.env.DEV_MODE === 'true') {
  return [{ json: { ...($json.body || $json), __hmac_skipped: true } }];
}

if (!signature) {
  return [{ json: { __hmac_error: 'missing_signature_header', statusCode: 401 } }];
}

let bodyForHmac = body;
if (typeof body === 'object') {
  bodyForHmac = JSON.stringify(body);
}

const expectedHmac = crypto
  .createHmac('sha256', Buffer.from(secret, 'hex'))
  .update(bodyForHmac, 'utf8')
  .digest('hex');

try {
  crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedHmac, 'hex')
  );
  return [{ json: { ...($json.body || $json), __hmac_validated: true } }];
} catch (err) {
  return [{ json: { __hmac_error: 'invalid_signature', statusCode: 401 } }];
}

const input = items[0]?.json?.body || items[0]?.json || {};
const MAX_FORMATS = 4, MAX_LANGS = 12, MAX_PLATFORMS = 5, MAX_CONCEPT_LEN = 1500;

const concept0 = String(input.concept || 'AdOff blocca la pubblicità invasiva').slice(0, MAX_CONCEPT_LEN);
const concept = concept0.replace(/[\u0000-\u001f\u007f]/g, '');

let formats = Array.isArray(input.formats) ? input.formats : ['thread'];
let langs = Array.isArray(input.langs) ? input.langs : ['it', 'en'];
let platforms = Array.isArray(input.platforms) ? input.platforms : ['twitter', 'instagram'];

formats = formats.slice(0, MAX_FORMATS).filter(f => /^[a-z_]{4,20}$/.test(f));
langs = langs.slice(0, MAX_LANGS).filter(l => /^[a-z]{2,5}$/i.test(l));
platforms = platforms.slice(0, MAX_PLATFORMS).filter(p => /^[a-z0-9_-]{2,30}$/.test(p));

if (formats.length === 0) formats = ['thread'];
if (langs.length === 0) langs = ['it'];
if (platforms.length === 0) platforms = ['twitter'];

const tone = String(input.tone || 'energica, brillante, diretta').slice(0, 300);
const source_seed_id = input.source_seed_id ? String(input.source_seed_id).slice(0, 100) : null;

const out = [];
for (const format of formats) {
  for (const lang of langs) {
    for (const platform of platforms) {
      const validCombos = {
        'thread': ['twitter'],
        'carousel': ['instagram', 'linkedin', 'facebook'],
        'reel_script': ['tiktok', 'instagram', 'reels'],
        'short_script': ['youtube', 'youtube-shorts']
      };
      const validPlatforms = validCombos[format] || [platform];
      if (!validPlatforms.includes(platform)) continue;

      out.push({
        json: {
          concept,
          format,
          lang,
          platform,
          tone,
          source_seed_id
        }
      });
    }
  }
}

if (out.length === 0) {
  return [{ json: { error: 'no_valid_format_lang_platform_combos' } }];
}

return out;

const { concept, format, lang, platform, tone } = $json;
if (format !== 'thread') return [{ json: $json }];

const LANG_NAMES = { it: 'italiano', en: 'English', de: 'Deutsch', fr: 'français', es: 'español', pt: 'português' };
const langName = LANG_NAMES[lang] || lang;

const prompt = `Sei copywriter brand AdOff. Crea un THREAD TWITTER in ${langName} su: ${concept}

VINCOLI ASSOLUTI:
1. MAI nominare brand famosi (YouTube, Google, Facebook, Instagram, TikTok, Twitter/X, Amazon, Reddit, Twitch, GitHub, LinkedIn). Usa sinonimi.
2. MAI scrivere "149 KB" o varianti.
3. Voice: ${tone}. Frasi brevi, ritmo alto.
4. 3-8 tweet collegati. Hook (tweet 1) deve catturare in 3 secondi. Body: ogni tweet 1 punto preciso. Conclusion: CTA soft per AdOff.
5. Max 280 caratteri per tweet.
6. Lingua: solo ${langName}.

RISTITUISCI SOLO JSON VALIDO:
{
  "hook_tweet": "max 280 char",
  "body_tweets": ["tweet 1", "tweet 2", ...],
  "conclusion_tweet": "CTA final, max 280",
  "hashtags": ["#tag1", "#tag2", ...]
}`;

return [{ json: { ...\$json, prompt, schema_type: 'thread' } }];

const { concept, format, lang, platform, tone } = $json;
if (format !== 'carousel') return [{ json: $json }];

const LANG_NAMES = { it: 'italiano', en: 'English', de: 'Deutsch', fr: 'français', es: 'español', pt: 'português' };
const langName = LANG_NAMES[lang] || lang;

const prompt = `Sei copywriter brand AdOff. Crea CAROUSEL SLIDES per ${platform.toUpperCase()} in ${langName} su: ${concept}

VINCOLI:
1. MAI brand famosi. Usa sinonimi.
2. MAI "149 KB".
3. Voice: ${tone}.
4. 5-8 slide (cover + intermedie + final CTA).
5. Cover: headline max 60 char, subtitle max 100 char.
6. Slide intermedie: headline max 50 char, body max 150 char.
7. Visual brief (1-2 righe per ogni slide) per guida designer.
8. Final slide: CTA AdOff trial.

RISTITUISCI SOLO JSON:
{
  "cover": {
    "title": "max 60 char",
    "subtitle": "max 100 char",
    "visual_brief": "description for designer"
  },
  "slides": [
    {"slide_num": 1, "headline": "max 50 char", "body": "max 150 char", "visual_brief": "..."}
  ],
  "final_cta_slide": {
    "headline": "CTA headline",
    "cta_text": "Try AdOff free for 15 days"
  }
}`;

return [{ json: { ...\$json, prompt, schema_type: 'carousel' } }];

const { concept, format, lang, platform, tone } = $json;
if (format !== 'reel_script') return [{ json: $json }];

const LANG_NAMES = { it: 'italiano', en: 'English', de: 'Deutsch', fr: 'français', es: 'español', pt: 'português' };
const langName = LANG_NAMES[lang] || lang;

const prompt = `Sei scriptwriter per Reel/TikTok. Crea script 15-60 sec in ${langName} su: ${concept}

VINCOLI:
1. MAI brand famosi. Sinonimi obbligatori.
2. MAI "149 KB".
3. Voice: ${tone}. Frasi cortissime.
4. Hook 0-3s: DEMOLIZIONER (pattern interrupt + reveal + curiosity).
5. Body beat scenes 3-50s: text overlay + action/cut description.
6. CTA last 3s: call-to-action soft AdOff.
7. Music brief: 1 parola (energetic/cinematic/playful).
8. Lingua: solo ${langName}.

RISTITUISCI SOLO JSON:
{
  "hook_seconds_0_3": "demolitore hook",
  "body_beats": [
    {"time_seconds": "4-8", "text": "voiceover/text", "action": "cut to ...", "text_overlay": "..."}
  ],
  "cta_seconds_last_3": "CTA text",
  "music_brief": "energetic",
  "total_duration_sec": 45
}`;

return [{ json: { ...\$json, prompt, schema_type: 'reel_script' } }];

const { concept, format, lang, platform, tone } = $json;
if (format !== 'short_script') return [{ json: $json }];

const LANG_NAMES = { it: 'italiano', en: 'English', de: 'Deutsch', fr: 'français', es: 'español', pt: 'português' };
const langName = LANG_NAMES[lang] || lang;

const prompt = `Sei scriptwriter per YouTube Shorts. Crea script 45-60 sec in ${langName} su: ${concept}

VINCOLI:
1. MAI brand famosi. Sinonimi.
2. MAI "149 KB".
3. Voice: ${tone}.
4. Hook first 3 sec: destabilizzante.
5. Narrative arc: problem → twist → solution → CTA.
6. B-roll suggestions per ogni beat.
7. Title 60 char: ottimizzato per CTR.
8. Description 140 char.
9. Tags: 5-7 rilevanti ("ad blocker", "privacy", etc).

RISTITUISCI SOLO JSON:
{
  "hook": "first 3 sec",
  "narrative_beats": [
    {"time": "0-10s", "voiceover": "VO text", "b_roll_suggestion": "..."}
  ],
  "cta": "last 5 sec CTA",
  "title_60char": "...",
  "description_140char": "...",
  "tags": ["#tag1", "#tag2"]
}`;

return [{ json: { ...\$json, prompt, schema_type: 'short_script' } }];

function normalizeForGuard(s) {
  if (!s) return '';
  return String(s)
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .toLowerCase()
    .replace(/[·•​-‍﻿⁠]/g, '')
    .replace(/\\s+/g, ' ');
}

function brandGuardCheck(rawText) {
  const t = normalizeForGuard(rawText);
  const BRANDS = ['youtube','you tube','google','facebook','face book','instagram','insta gram','tiktok','tik tok','tik-tok','twitter','\\bx\\b','amazon','reddit','twitch','github','linkedin'];
  for (const b of BRANDS) {
    const rx = new RegExp(b, 'iu');
    if (rx.test(t)) return { ok: false, hit: b };
  }
  if (/149[\\s\\-_]*k(?:ilo)?b(?:yte)?s?/iu.test(t)) return { ok: false, hit: '149kb' };
  return { ok: true };
}

const meta = $json;
const resp = $json;
let text = '';
try { text = resp.candidates?.[0]?.content?.parts?.[0]?.text || ''; } catch(e){}

let parsed = null;
try { parsed = JSON.parse(text); } catch(e) {
  const m = text.match(/\\{[\\s\\S]*\\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch(e2){} }
}

if (!parsed) {
  return [{ json: { ...meta, ok: false, reason: 'gemini_no_valid_json', raw: text.slice(0, 300) } }];
}

const fullText = JSON.stringify(parsed);
const guard = brandGuardCheck(fullText);
if (!guard.ok) {
  return [{ json: { ...meta, ok: false, reason: 'brand_guard_' + guard.hit, preview: fullText.slice(0, 200) } }];
}

return [{ json: { ...meta, ok: true, body_json: JSON.stringify(parsed), model: 'gemini-2.5-flash', tokens_in: resp.usageMetadata?.promptTokenCount || 0, tokens_out: resp.usageMetadata?.candidatesTokenCount || 0 } }];
